using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "BlogDb",
            cosmosOptions =>
            {
                // Breaking change #4: Sync I/O now throws by default in EF9.
                // Use async APIs (preferred) or opt in here for legacy code paths.
                cosmosOptions.AllowSynchronousIO();
            });
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #1: EF9 renamed the discriminator property from
        // "Discriminator" to "$type". Existing documents store "Discriminator",
        // so pin the old name to keep them readable.
        modelBuilder.Entity<Blog>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Blog>("Blog");

        // Breaking change #2: EF9 changed the Cosmos `id` value from
        // "{Discriminator}|{Key}" to just "{Key}".
        // Existing documents use "Blog|1" format — preserve it.
        modelBuilder.Entity<Blog>()
            .Property<string>("__id")
            .ToJsonProperty("id")
            .HasValueGenerator<LegacyCosmosIdGenerator>();

        // Breaking change #3: HasIndex() now throws for the Cosmos provider.
        // It was silently ignored in EF8 — remove it.
        // REMOVED: modelBuilder.Entity<Blog>().HasIndex(b => b.Name);
    }
}

/// <summary>
/// Generates Cosmos document ids in the pre-EF9 "{Discriminator}|{Key}" format
/// so the application stays compatible with existing documents.
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString();
        var pk = entry.Metadata.FindPrimaryKey()!.Properties[0];
        var key = entry.Property(pk.Name).CurrentValue;
        return $"{discriminator}|{key}";
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

