 using Microsoft.EntityFrameworkCore;
 using System.Threading.Tasks;

 class SyncJob
 {
     // Breaking change #4: EF9 Cosmos provider no longer supports synchronous
     // I/O by default. Prefer async APIs (ToListAsync / SaveChangesAsync).
     async Task RunAsync(BlogContext context)
     {
         var blogs = await context.Blogs.ToListAsync();
         foreach (var b in blogs) { b.Name = b.Name.Trim(); }
         await context.SaveChangesAsync();
     }
 }
